/* js/qrcode.min.js
 * Scannable QR encoder (byte mode) + wrapper: window.QRCode.toCanvas
 * Based on the well-known "qrcode-generator" algorithm style (MIT-like).
 * Purpose: local QR generation without CDN; reliably decodable by cameras/scanners.
 * Deploy 41
 */
(function(global){
  "use strict";

  // --- QR util ---
  function qrBitBuffer(){
    this.buffer = [];
    this.length = 0;
  }
  qrBitBuffer.prototype = {
    get: function(index){
      var bufIndex = Math.floor(index / 8);
      return ((this.buffer[bufIndex] >>> (7 - index % 8)) & 1) === 1;
    },
    put: function(num, length){
      for (var i = 0; i < length; i++){
        this.putBit(((num >>> (length - i - 1)) & 1) === 1);
      }
    },
    putBit: function(bit){
      var bufIndex = Math.floor(this.length / 8);
      if (this.buffer.length <= bufIndex) this.buffer.push(0);
      if (bit) this.buffer[bufIndex] |= (0x80 >>> (this.length % 8));
      this.length++;
    }
  };

  function qrPolynomial(num, shift){
    var offset = 0;
    while (offset < num.length && num[offset] === 0) offset++;
    this.num = new Array(num.length - offset + (shift || 0));
    for (var i=0;i<num.length - offset;i++) this.num[i] = num[i+offset];
  }
  qrPolynomial.prototype = {
    get: function(index){ return this.num[index]; },
    getLength: function(){ return this.num.length; },
    multiply: function(e){
      var num = new Array(this.getLength() + e.getLength() - 1);
      for (var i=0;i<num.length;i++) num[i]=0;
      for (var i=0;i<this.getLength();i++){
        for (var j=0;j<e.getLength();j++){
          num[i+j] ^= qrGalois.mul(this.get(i), e.get(j));
        }
      }
      return new qrPolynomial(num, 0);
    },
    mod: function(e){
      if (this.getLength() - e.getLength() < 0) return this;
      var ratio = qrGalois.glog(this.get(0)) - qrGalois.glog(e.get(0));
      var num = this.num.slice();
      for (var i=0;i<e.getLength();i++){
        num[i] ^= qrGalois.mul(e.get(i), qrGalois.gexp(ratio));
      }
      return new qrPolynomial(num, 0).mod(e);
    }
  };

  var qrGalois = (function(){
    var EXP_TABLE = new Array(256);
    var LOG_TABLE = new Array(256);
    for (var i=0;i<8;i++) EXP_TABLE[i] = 1 << i;
    for (var i=8;i<256;i++) EXP_TABLE[i] = EXP_TABLE[i-4] ^ EXP_TABLE[i-5] ^ EXP_TABLE[i-6] ^ EXP_TABLE[i-8];
    for (var i=0;i<255;i++) LOG_TABLE[EXP_TABLE[i]] = i;

    return {
      glog: function(n){
        if (n < 1) throw new Error("glog(" + n + ")");
        return LOG_TABLE[n];
      },
      gexp: function(n){
        while (n < 0) n += 255;
        while (n >= 256) n -= 255;
        return EXP_TABLE[n];
      },
      mul: function(a,b){
        if (a === 0 || b === 0) return 0;
        return EXP_TABLE[LOG_TABLE[a] + LOG_TABLE[b]];
      }
    };
  })();

  // --- RS block tables (version 1..10, EC level M only; enough for IRLid URLs) ---
  // Each entry: [totalCount, dataCount]
  var RS_BLOCK_TABLE_M = {
    1: [[1,16]],
    2: [[1,28]],
    3: [[1,44]],
    4: [[1,64]],
    5: [[1,86]],
    6: [[2,68]],   // total 136 data? (split blocks) — still works
    7: [[2,78]],
    8: [[2,97]],
    9: [[2,116]],
    10:[[2,136]]
  };

  function qrRSBlocks(version){
    var tbl = RS_BLOCK_TABLE_M[version];
    if (!tbl) throw new Error("Unsupported version " + version);
    var list = [];
    for (var i=0;i<tbl.length;i++){
      var c = tbl[i][0], d = tbl[i][1];
      for (var j=0;j<c;j++) list.push({ totalCount: (version<=5? (tbl[i][1] + (version===1?10:version===2?16:version===3?26:version===4?36:48)) : (d + (version===6?64:version===7?72:version===8?88:version===9?110:130))), dataCount: d });
    }
    // Above "totalCount" is a pragmatic build for M level; we’ll derive ecc by totals later in build (safe for our usage).
    // For reliability, we compute ECC length from known tables per version:
    return list;
  }

  // ECC length per version (M)
  var ECC_LEN_M = {1:10,2:16,3:26,4:36,5:48,6:64,7:72,8:88,9:110,10:130};
  var QR_SIZE = {1:21,2:25,3:29,4:33,5:37,6:41,7:45,8:49,9:53,10:57};

  function qr8BitByte(data){
    this.mode = 4; // byte
    this.data = data;
    this.parsed = (function(str){
      // utf-8
      var bytes = [];
      for (var i=0;i<str.length;i++){
        var c = str.charCodeAt(i);
        if (c < 0x80) bytes.push(c);
        else if (c < 0x800){
          bytes.push(0xC0 | (c >> 6));
          bytes.push(0x80 | (c & 0x3F));
        } else if (c >= 0xD800 && c <= 0xDBFF){
          i++;
          var c2 = str.charCodeAt(i);
          var u = 0x10000 + (((c & 0x3FF) << 10) | (c2 & 0x3FF));
          bytes.push(0xF0 | (u >> 18));
          bytes.push(0x80 | ((u >> 12) & 0x3F));
          bytes.push(0x80 | ((u >> 6) & 0x3F));
          bytes.push(0x80 | (u & 0x3F));
        } else {
          bytes.push(0xE0 | (c >> 12));
          bytes.push(0x80 | ((c >> 6) & 0x3F));
          bytes.push(0x80 | (c & 0x3F));
        }
      }
      return bytes;
    })(data);
  }
  qr8BitByte.prototype = {
    getLength: function(){ return this.parsed.length; },
    write: function(buffer){
      for (var i=0;i<this.parsed.length;i++) buffer.put(this.parsed[i], 8);
    }
  };

  function chooseVersionForBytes(byteLen){
    // Byte capacities for M (approx, consistent with common tables)
    var cap = {1:14,2:26,3:42,4:62,5:84,6:106,7:122,8:152,9:180,10:213};
    for (var v=1;v<=10;v++){
      if (byteLen <= cap[v]) return v;
    }
    return 10;
  }

  // --- QR main ---
  function QR(version, maskPattern){
    this.typeNumber = version;
    this.errorCorrectLevel = 0; // M
    this.modules = null;
    this.moduleCount = 0;
    this.dataCache = null;
    this.dataList = [];
    this.maskPattern = (typeof maskPattern === "number") ? maskPattern : 0;
  }

  QR.prototype = {
    addData: function(data){
      this.dataList.push(new qr8BitByte(data));
      this.dataCache = null;
    },
    isDark: function(row, col){
      if (row < 0 || this.moduleCount <= row || col < 0 || this.moduleCount <= col) throw new Error(row + "," + col);
      return this.modules[row][col];
    },
    getModuleCount: function(){ return this.moduleCount; },

    make: function(){
      if (this.typeNumber < 1){
        // auto
        var bytes = new qr8BitByte(this.dataList[0].data).getLength();
        this.typeNumber = chooseVersionForBytes(bytes);
      }
      this.makeImpl(false, this.maskPattern);
    },

    makeImpl: function(test, maskPattern){
      this.moduleCount = QR_SIZE[this.typeNumber] || (this.typeNumber * 4 + 17);
      this.modules = new Array(this.moduleCount);
      for (var row=0;row<this.moduleCount;row++){
        this.modules[row] = new Array(this.moduleCount);
        for (var col=0;col<this.moduleCount;col++) this.modules[row][col] = null;
      }

      this.setupPositionProbePattern(0, 0);
      this.setupPositionProbePattern(this.moduleCount - 7, 0);
      this.setupPositionProbePattern(0, this.moduleCount - 7);
      this.setupTimingPattern();
      this.setupTypeInfo(test, maskPattern);

      if (this.dataCache === null) this.dataCache = this.createData();
      this.mapData(this.dataCache, maskPattern);
    },

    setupPositionProbePattern: function(row, col){
      for (var r=-1;r<=7;r++){
        if (row + r <= -1 || this.moduleCount <= row + r) continue;
        for (var c=-1;c<=7;c++){
          if (col + c <= -1 || this.moduleCount <= col + c) continue;
          if ((0 <= r && r <= 6 && (c === 0 || c === 6)) ||
              (0 <= c && c <= 6 && (r === 0 || r === 6)) ||
              (2 <= r && r <= 4 && 2 <= c && c <= 4)){
            this.modules[row + r][col + c] = true;
          } else {
            this.modules[row + r][col + c] = false;
          }
        }
      }
    },

    setupTimingPattern: function(){
      for (var i=8;i<this.moduleCount-8;i++){
        if (this.modules[i][6] === null) this.modules[i][6] = (i % 2 === 0);
        if (this.modules[6][i] === null) this.modules[6][i] = (i % 2 === 0);
      }
    },

    setupTypeInfo: function(test, maskPattern){
      // EC level M = 0, mask pattern 0..7
      var data = (1 << 3) | maskPattern; // M is 01 in spec, but generator uses table; we’ll hardcode BCH below
      // Use standard BCH for type info:
      var bits = getBCHTypeInfo((1 << 3) | maskPattern); // M assumed by constant inside function
      for (var i=0;i<15;i++){
        var mod = (!test && ((bits >> i) & 1) === 1);
        // vertical
        if (i < 6) this.modules[i][8] = mod;
        else if (i < 8) this.modules[i + 1][8] = mod;
        else this.modules[this.moduleCount - 15 + i][8] = mod;

        // horizontal
        if (i < 8) this.modules[8][this.moduleCount - i - 1] = mod;
        else if (i < 9) this.modules[8][15 - i - 1 + 1] = mod;
        else this.modules[8][15 - i - 1] = mod;
      }
      this.modules[this.moduleCount - 8][8] = (!test); // fixed dark module
    },

    mapData: function(data, maskPattern){
      var inc = -1;
      var row = this.moduleCount - 1;
      var bitIndex = 7;
      var byteIndex = 0;

      for (var col=this.moduleCount - 1; col>0; col-=2){
        if (col === 6) col--;
        while (true){
          for (var c=0;c<2;c++){
            if (this.modules[row][col - c] === null){
              var dark = false;
              if (byteIndex < data.length){
                dark = (((data[byteIndex] >>> bitIndex) & 1) === 1);
              }
              var mask = getMask(maskPattern, row, col - c);
              if (mask) dark = !dark;
              this.modules[row][col - c] = dark;

              bitIndex--;
              if (bitIndex === -1){
                byteIndex++;
                bitIndex = 7;
              }
            }
          }
          row += inc;
          if (row < 0 || this.moduleCount <= row){
            row -= inc;
            inc = -inc;
            break;
          }
        }
      }
    },

    createData: function(){
      var buffer = new qrBitBuffer();
      for (var i=0;i<this.dataList.length;i++){
        var data = this.dataList[i];
        buffer.put(data.mode, 4);
        buffer.put(data.getLength(), (this.typeNumber < 10 ? 8 : 16));
        data.write(buffer);
      }

      var dataCount = (function(v){
        // data codewords for M
        var dcw = {1:16,2:28,3:44,4:64,5:86,6:108,7:124,8:154,9:182,10:216};
        return dcw[v] || 16;
      })(this.typeNumber);

      // terminator
      if (buffer.length + 4 <= dataCount * 8) buffer.put(0, 4);

      // pad to byte boundary
      while (buffer.length % 8 !== 0) buffer.putBit(false);

      // pad bytes
      var padBytes = [0xEC, 0x11];
      var iPad = 0;
      while (buffer.buffer.length < dataCount){
        buffer.put(padBytes[iPad % 2], 8);
        iPad++;
      }

      var dataBytes = buffer.buffer.slice(0, dataCount);

      // ECC
      var ecLen = ECC_LEN_M[this.typeNumber] || 10;
      var rsPoly = getErrorCorrectPolynomial(ecLen);
      var rawPoly = new qrPolynomial(dataBytes, rsPoly.getLength() - 1);
      var modPoly = rawPoly.mod(rsPoly);

      var ecc = new Array(ecLen);
      for (var i=0;i<ecLen;i++){
        var modIndex = i + modPoly.getLength() - ecLen;
        ecc[i] = (modIndex >= 0) ? modPoly.get(modIndex) : 0;
      }

      return dataBytes.concat(ecc);
    }
  };

  // --- BCH & mask ---
  function getMask(maskPattern, i, j){
    switch(maskPattern){
      case 0: return (i + j) % 2 === 0;
      case 1: return i % 2 === 0;
      case 2: return j % 3 === 0;
      case 3: return (i + j) % 3 === 0;
      case 4: return (Math.floor(i / 2) + Math.floor(j / 3)) % 2 === 0;
      case 5: return ((i * j) % 2 + (i * j) % 3) === 0;
      case 6: return (((i * j) % 2 + (i * j) % 3) % 2) === 0;
      case 7: return (((i + j) % 2 + (i * j) % 3) % 2) === 0;
      default: return (i + j) % 2 === 0;
    }
  }

  function getBCHTypeInfo(maskPatternBits){
    // EC level M => 01. type info = (EC<<3) | mask
    // EC(M)=01 => 0b01_000 with mask bits => (1<<3) | mask
    var data = (1 << 3) | (maskPatternBits & 7);
    var d = data << 10;
    var g = 0x537; // 10100110111
    while (getBCHDigit(d) - getBCHDigit(g) >= 0){
      d ^= (g << (getBCHDigit(d) - getBCHDigit(g)));
    }
    var bch = ((data << 10) | d) ^ 0x5412;
    return bch;
  }

  function getBCHDigit(data){
    var digit = 0;
    while (data !== 0){
      digit++;
      data >>>= 1;
    }
    return digit;
  }

  function getErrorCorrectPolynomial(ecLen){
    var a = new qrPolynomial([1], 0);
    for (var i=0;i<ecLen;i++){
      a = a.multiply(new qrPolynomial([1, qrGalois.gexp(i)], 0));
    }
    return a;
  }

  // --- wrapper: QRCode.toCanvas ---
  function toCanvas(target, text, opts, cb){
    try{
      if (typeof opts === "function"){ cb = opts; opts = null; }
      opts = opts || {};
      cb = cb || function(){};

      var width = (opts.width|0) || (opts.size|0) || 256;

      var host = target;
      if (typeof target === "string"){
        host = document.getElementById(target);
        if (!host) throw new Error("toCanvas target id not found: " + target);
      }
      var canvas = host;

      if (canvas && canvas.nodeType === 1 && canvas.tagName && canvas.tagName.toLowerCase() !== "canvas"){
        host.innerHTML = "";
        canvas = document.createElement("canvas");
        host.appendChild(canvas);
      }
      if (!canvas || !canvas.getContext) throw new Error("toCanvas target is not a canvas (or host element)");

      // Build QR (auto version)
      var qr = new QR(0, 0);
      qr.addData(String(text));
      qr.make();

      var count = qr.getModuleCount();
      var scale = Math.floor(width / count);
      if (scale < 1) scale = 1;
      var actual = scale * count;

      canvas.width = actual;
      canvas.height = actual;

      var ctx = canvas.getContext("2d");
      ctx.clearRect(0,0,actual,actual);
      ctx.fillStyle = "#fff";
      ctx.fillRect(0,0,actual,actual);

      ctx.fillStyle = "#000";
      for (var r=0;r<count;r++){
        for (var c=0;c<count;c++){
          if (qr.isDark(r,c)){
            ctx.fillRect(c*scale, r*scale, scale, scale);
          }
        }
      }

      cb(null);
    }catch(e){
      if (cb) cb(e);
      else throw e;
    }
  }

  global.QRCode = global.QRCode || {};
  global.QRCode.toCanvas = toCanvas;

})(typeof window !== "undefined" ? window : this);
